const IMAGE_SELECTOR='img';

function normalizeImage(img){
  if(!img)return;

  const currentSrc=img.getAttribute('src');
  const dataSrc=img.dataset?.src;

  if((!currentSrc||currentSrc.trim()==='')&&dataSrc){
    img.src=dataSrc;
  }

  if(img.dataset?.src&&img.getAttribute('src')){
    delete img.dataset.src;
  }

  if(!img.hasAttribute('loading')){
    img.loading='lazy';
  }

  if(!img.hasAttribute('decoding')){
    img.decoding='async';
  }
}

function normalizeAllImages(root=document){
  root.querySelectorAll(IMAGE_SELECTOR).forEach(normalizeImage);
}

if(document.readyState==='loading'){
  document.addEventListener('DOMContentLoaded',()=>normalizeAllImages());
}else{
  normalizeAllImages();
}

window.restoreImageSources=normalizeAllImages;
